
#include "svg_helper.h"
int main(){string stem="10_decision_tree_lower_bound",title="10 Decision Tree Lower Bound"; vector<string> f={"comparison sort as binary tree","each leaf is one permutation","need at least n! leaves","height is lower bound"}; for(int k=0;k<6;++k){int W=1140,H=680; string s=startSVG(W,H,title,"Step "+to_string(k+1)+" / 6 - comparison decision tree"); s+=box(50,120,610,400,"#fff","#bfd3e6"); s+=T(90,155,"Decision tree: every comparison branches yes/no",17,"#123","700"); vector<pair<int,int>> p={{330,190},{210,280},{450,280},{150,370},{270,370},{390,370},{510,370}}; vector<string> lab={"a<b?","a<c?","b<c?","abc","acb","bac","bca"}; int show=min(7,1+k); for(int i=0;i<show;i++){s+=box(p[i].first,p[i].second,70,42,i>=3?"#dcfce7":"#e0f2fe","#64748b"); s+=T(p[i].first+8,p[i].second+27,lab[i],14,"#123","700");} vector<pair<int,int>> e={{0,1},{0,2},{1,3},{1,4},{2,5},{2,6}}; for(int i=0;i<min((int)e.size(),k);++i){auto [u,v]=e[i]; s+=arrow(p[u].first+35,p[u].second+42,p[v].first+35,p[v].second,"#64748b",2);} s+=T(90,475,"For n records, comparison sorting requires enough leaves for all n! permutations.",16,"#111827","700"); s+=T(90,505,"Therefore worst-case height is at least log2(n!) = Omega(n log n).",16,"#b91c1c","700"); s+=sidebar(k+1,6,f)+footer(W,H,stem+".cpp"); stringstream path; path<<"output/"<<stem<<"_steps/step_"<<setw(2)<<setfill('0')<<k+1<<".svg"; writeFile(path.str(),s+endSVG());}}
